#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret = texture( sampler_main, vUv ).xyz;

float1 a = vUv.x;
float1 b = vUv.y;
float1 ca;
float1 cb;
float1 golden = 1.6180339887;
// ca; 0       ; (golden-2); 0.285; 0.285; 0.45  ; -0.70176; -0.835 ; -0.8 ; -0.7269
// cb; 1-golden; (golden-1); 0    ; 0.01 ; 0.1428; -0.3842 ; -0.2321; 0.156; 0.1889

if(q9 == 5){
    ca = 0.285;
    cb = 0;
}
else if(q9 == 6){
    ca = -0.66176 + 0.03*sin(0.25*uTime + 0.014*q5);
    cb = -0.3842;
}
// q9 does equal 7
else if(q9 == 7) {
    ca = -0.7069 + 0.03*sin(0.2*uTime + 0*0.012*q5) ;
    cb = 0.138 + 0.04*cos(uTime*0.4 + 0*0.03*q5);
}
else { // if q9 = 0
    ca = a;
    cb = b;
}
float1 aa;
float1 bb;

float1 n = 0;
float1 maxiter = 60;
float1 m=0;
float1 r = 1000;
float1 r2 = r*r;
vec3 col;

float1 pa;
float1 pb;
vec2 z;
vec2 pz;
float leaves = 0.4*(q5+q6+q7)*0.3; // speed for the leaves
while(n < maxiter && m==0)
{
    aa = a*a - b*b;
    bb = 2*a*b;
    pa = a;
    pb = b;
    pz = vec2(pa*cos(leaves*0.5) - pb*sin(leaves*0.5),pa*sin(leaves*0.5) + pb*cos(leaves*0.5));
    a = aa + ca;
    b = bb + cb;
    z = vec2(a,b);

    //if(sqrt(pow(a-pa,2) + pow(b-pb,2)) > r2)
    //if(dot(z,pz) > r2)
    //if(sqrt(a*a + b*b) > r2)
    if(dot(z + 4000*q25,pz + 60*q26) > r2)
    {
        m = 1;
    }
    else
    {
        n++;
    }
}

col = texture(sampler_colors14, vec2(0.5 + 0.4*sin(n*0.4 + 0*0.2*uTime + 0.01*(q5+q6+q7)),0.5 + 0.4*cos(n*0.1 + 0*0.4*uTime + 0.015*(q5+q6+q7)))).xyz;
//col = pow(col,6);
//col*=40;
col = pow(col,4);
col*=2;
float beat = (q13 + q12 + q14)/3;
col*= 0.3 + vec3(beat,beat,beat);

float1 dist = (sqrt(a*a + b*b));
float1 fraciter = (dist - r) / (r2 - r);
fraciter = log2(log(dist) / log(r)) ;
n -= fraciter;
vec3 color;
color.x = 0.5 + 0.5*sin(0.09*n*1.5 + 0*0.7*uTime + 0.2*q5);
color.y = 0.5 + 0.5*sin(0.09*n*1.5 + 0*0.7*uTime + 0.2*q6);
color.z = 0.5 + 0.5*sin(0.09*n*1.5 + 0*0.7*uTime + 0.2*q7);

float rotspeed = sin(0.02*q5);
vec2 uvrot = vUv;
uvrot = vec2(cos(rotspeed)*uvrot.x - sin(rotspeed)*uvrot.y, sin(rotspeed)*uvrot.x + cos(rotspeed)*uvrot.y);

// background stars
vec3 backstars1 = backstarsf(uvrot + 0.1*uTime, 50);
vec3 backstars2 = backstarsf(uvrot + 0.12*uTime, 20);
vec3 backstars3 = backstarsf(uvrot + 0.14*uTime, 10);
vec3 backstars4 = backstarsf(uvrot + 0.16*uTime, 7);
//vec3 backstars5 = backstarsf(uvrot + 3*uTime, 1);
float backstars = backstars1 + backstars2 + backstars3 + backstars4; // make it vec3 to add colors for the stars
backstars *= 4*max(0.2, 0.05 + 0.5*min(1,max(0,audioMidSmooth-1)*1.3));

// ### moving stars by martin ###

vec2 uv_temp = vUv;
vUv = uvrot;
vUv-=vec2(q31,q32);
rs0.x = atan(vUv.x, vUv.y)/3.1416*2;
rs0.y = .05/(length(vUv));
rss = vec2 (rs0.x,rs0.y + q10 + uTime*0.1);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
float noise = (texture(sampler_pw_noise_lq,rss/32)-.7 >= 0);
rss = abs(fract(rss*8)-0.5);
vec3 dots = 0;
dots = clamp01(.06/length(rss)) *noise;

rss = vec2 (rs0.x*2,rs0.y + q11 + uTime*0.05);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
noise = (texture(sampler_pw_noise_lq,rss/32)-.7 >= 0);
rss = abs(fract(rss*8)-.5);
dots += clamp01(.04/length(rss)) * noise;

dots *= clamp01(.04/abs(.01/rs0.y-0))+.0;
dots *= dots;
// ### End of stars ###

float angle = atan(z.x, z.y);

if(m == 1) // inside of the mandelbrot set
{
    ret = col;
    float q = smoothstep(1.6,0,fraciter)*3; // darker leaves
    ret *= q;
    //ret *= 1 + smoothstep(0.5,0.1,fraciter)*3;
    ret *= 1+sin(angle*2 + leaves*2)*3; // add lines to the leaves, multiply the angle for more leaves
}
else // outside of the mandelbrot set
{
    ret = 0;
    vec2 sunpos = vec2(q31,q32);
    float circle = Dist(vUv,sunpos);
    float circler = 0.17;
    ret += dots;
    ret += backstars;
    if(circle < circler) // add sun
    {
        vec3 sun = 4*texture(sampler_sun, (vUv*uTexSize.xy + 0.5*uFrame)*texsize_sun.zw).xyz;
        sun *= 0.9*smoothstep(circler,circler-0.045, circle);
        ret += vec3(1,0.8,0)*sun*0.8;
        ret += sun*0.16*vec3(0.8,1,3*(q1+q2+q3));
    }
    ret += 0.2*vec3(0.4*(q1+q2+q3),0.2,1)*smoothstep(circler+0.5, circler, circle);

}

vUv = uv_temp;

//if(sqrt(vUv.x*vUv.x + vUv.y*vUv.y)<0.05) {ret = 1;}
//ret*=1.6;
//vUv-=0.5;
//ret = vec3(vUv.x,vUv.y,0);

  fragColor = ret;
}

